#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long *A = (long long*)malloc(N*sizeof(long long));
        long long total=0;
        for(int i=0;i<N;i++){
            scanf("%lld", &A[i]);
            total+=A[i];
        }
        if(K> N){
            printf("0\n");
            free(A);
            continue;
        }
        long long low=0, high= total/ K, ans=0;
        while(low<=high){
            long long mid = (low+high)/2;
            __int128 sum=0;
            for(int i=0;i<N;i++){
                sum += (A[i] < mid) ? A[i] : mid;
                if(sum >= (__int128)mid*K) break; // early stop
            }
            if(sum >= (__int128)mid*K){
                ans=mid; low=mid+1;
            }else high=mid-1;
        }
        printf("%lld\n", ans);
        free(A);
    }
    return 0;
}

