  const bigK = BigInt(K);
  let low = 0n, high = total / bigK, ans = 0n;
  while (low <= high) {
    const mid = (low + high) >> 1n;
    const need = mid * bigK;
    let sum = 0n;
    for (let i = 0; i < N; i++) {
      sum += A[i] < mid ? A[i] : mid;
      if (sum >= need) break;
    }
    if (sum >= need) { ans = mid; low = mid + 1n; }
    else { high = mid - 1n; }
  }
  out.push(ans.toString());
